urlset:
{{- $siteUrl := site.Params.siteUrl }}
{{ range .Data.Pages }}

    {{ $siteUrl }}{{ .RelPermalink }}{{ if not .Lastmod.IsZero }}
    {{ safeHTML ( .Lastmod.Format "2006-01-02T15:04:05-07:00" ) }}{{ end }}
    {{ if .IsHome }}weekly{{ else if eq .Section "blog" }}monthly{{ else }}yearly{{ end }}
    {{ if .IsHome }}1.0{{ else if eq .Section "work" }}0.9{{ else if eq .Section "blog" }}0.7{{ else }}0.5{{ end }}

{{ end }}
